# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
import requests

app = Flask(__name__)

# Dictionary to store annotations
annotations = {}

@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    
    if image_id not in annotations:
        annotations[image_id] = []
    
    annotations[image_id].append(label)
    
    return jsonify({'status': 'success'}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate():
    aggregated_labels = {}
    
    for image_id, labels in annotations.items():
        if len(labels) > 0:
            majority_label = max(set(labels), key=labels.count)
            aggregated_labels[image_id] = majority_label
    
    return jsonify(aggregated_labels)

@app.route('/train', methods=['POST'])
def train():
    aggregated_data = request.json
    # Placeholder for model training logic
    print("Training model with data:", aggregated_data)
    
    return jsonify({'status': 'training initiated'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)